import type React from 'react';

import { Slot } from '@radix-ui/react-slot';
import { cva, type VariantProps } from 'class-variance-authority';

import { cn } from '../utils/cn';
import { spacingLength } from '../utils/tw3-compat';

const flexVariants = cva('flex gap-[var(--gap)]', {
  variants: {
    direction: {
      row: 'flex-row',
      col: 'flex-col',
    },
  },
});

type AnyFlexComponentProps = React.ComponentProps<'div'> & {
  /** Set gap between items, in spacing units */
  spacing?: number;
};

type FlexProps = AnyFlexComponentProps &
  VariantProps<typeof flexVariants> & {
    asChild?: boolean;
    /** Set gap between items, in spacing units */
  };

/**
 * A thin abstraction around a flex container.
 */
function Flex({
  asChild,
  className,
  direction = 'row',
  spacing = 0,
  ...props
}: FlexProps) {
  const Comp = asChild ? Slot : 'div';
  return (
    <Comp
      style={{ '--gap': spacingLength(spacing) } as React.CSSProperties}
      className={cn(flexVariants({ direction }), className)}
      {...props}
    />
  );
}

/**
 * Convenience wrapper around Flex to set the direction to row.
 */
function FlexRow({ ...props }: AnyFlexComponentProps) {
  return <Flex direction="row" {...props} />;
}

/**
 * Convenience wrapper around Flex to set the direction to column.
 */
function FlexColumn({ ...props }: AnyFlexComponentProps) {
  return <Flex direction="col" {...props} />;
}

export { Flex, FlexRow, FlexColumn };
